"use client";

import { useState } from "react";
import Link from "next/link";
import Image from "next/image";
import { useRouter } from "next/navigation";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card } from "@/components/ui/card";
import { Mail, Lock, ArrowLeft } from "lucide-react";

import { login } from "@/lib/auth";

export default function LoginPage() {
  const router = useRouter();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    try {
      const data = await login(email, password);

      localStorage.setItem("token", data.token);
      localStorage.setItem("role", data.user.role);

      document.cookie = `token=${data.token}; path=/`;
      document.cookie = `role=${data.user.role}; path=/`;

      const role = data.user.role;

      if (role === "ADMIN") return router.push("/admin/dashboard");
      if (role === "USER" || role === "CUSTOMER") return router.push("/");

      if (role === "OWNER") {
        const status = data.user.profile_status;

        if (status === "pending") return router.push("/owner/pending");
        if (status === "rejected")
          return router.push(`/owner/rejected?reason=${data.user.reject_reason}`);

        return router.push("/owner/dashboard");
      }

      router.push("/");
    } catch (err: any) {
      setError("Email hoặc mật khẩu không đúng!");
    }
  };

  return (
    <main className="min-h-screen flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        <Link href="/" className="flex items-center gap-2 text-primary mb-8">
          <ArrowLeft className="w-4 h-4" /> Về Trang Chủ
        </Link>

        <Card className="p-8">
          <div className="text-center mb-8">
            <Image src="/hcmut-logo.png" width={64} height={64} alt="Logo" />
            <h1 className="text-3xl font-bold mt-4">Chào Mừng Trở Lại</h1>
          </div>

          {error && <p className="text-red-500 mb-4 text-center">{error}</p>}

          <form onSubmit={handleLogin} className="space-y-4">
            <Input
              type="email"
              placeholder="you@example.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />

            <Input
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />

            <Button type="submit" className="w-full">
              Đăng Nhập
            </Button>
          </form>
        </Card>
      </div>
    </main>
  );
}
